// Solution
function solve() {
    const readline = require('readline').createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let n;
    let arr = [];

    readline.question('Enter the number of elements: ', (nInput) => {
        n = parseInt(nInput);

        readline.question(`Enter ${n} elements: `, (input) => {
            arr = input.split(' ').map(Number);

            for (let i = 0; i < n-1; i++) {
                let swapped = false;
                for (let j = 0; j < n-i-1; j++) {
                    if (arr[j] > arr[j+1]) {
                        // swap arr[j] and arr[j+1]
                        let temp = arr[j];
                        arr[j] = arr[j+1];
                        arr[j+1] = temp;
                        swapped = true;
                    }
                }
                if (!swapped) break;
            }

            console.log(arr.join(' '));

            readline.close();
        });
    });
}

